1021954Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.2","depends_on_id":"bd-j9jo3.7","type":"parent-child","created_at":"2026-03-21T23:38:21.404153219Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.2","depends_on_id":"bd-j9jo3.7.1","type":"blocks","created_at":"2026-03-21T23:38:34.698286577Z","created_by":"ubuntu","metadata":"{}","thread_id":""}],"comments":[{"id":336,"issue_id":"bd-j9jo3.7.2","author":"ubuntu","text":"Watch-semantics follow-up: registry-backed capabilities and help should expose event classes, supported selectors or filters, heartbeat semantics, replay-to-live behavior, and whether a surface emits durable events, ephemeral keepalives, or both.","created_at":"2026-03-22T00:49:02Z"}]}
 {"id":"bd-j9jo3.7.3","title":"robot-redesign/registry: define registry-backed metadata for machine consumers and summary views","description":"Define the additional registry-backed metadata needed by machine consumers, summary views, and future transport integrations. This task exists because once a registry exists, ntm should use it to make machine integration more ergonomic instead of stopping at help text, especially around how consumers discover limits, drill-down paths, and compression semantics.","design":"The metadata may include stable section descriptions, consumer guidance, field-level or section-level summary hints, transport availability markers, replacement or removal markers when surfaces change, boundedness metadata such as default limits, truncation behavior, pagination support, recommended follow-up inspect surfaces, structured action-handoff hints, request or correlation semantics, whether a surface emits or accepts idempotency material, supported attention-state operations such as acknowledge or snooze or pin, and explainability metadata such as diagnostic entry points, explanation-handle semantics, evidence-summary availability, and aggregation or resurfacing cues for compacted attention items. The key is to expose enough structured meaning that agents and transport layers do less guesswork. This task should remain pragmatic: only encode metadata that improves real consumers.","acceptance_criteria":"This task is complete when downstream machine consumers and summary generators can obtain useful structured metadata from the registry, including how to interpret bounded or compressed views, how to correlate requests and outcomes, and how operator attention state changes what is shown, hidden, or force-prioritized.","notes":"This is one of the cleaner ways to steal ideas from vibe_cockpit's registry discipline without overbuilding a framework.","status":"open","priority":2,"issue_type":"task","estimated_minutes":150,"created_at":"2026-03-21T23:38:22.378960630Z","created_by":"ubuntu","updated_at":"2026-03-22T00:49:03.579613751Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["consumers","registry","robot-redesign"],"dependencies":[{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.1.10","type":"blocks","created_at":"2026-03-22T00:23:33.580146527Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.1.11","type":"blocks","created_at":"2026-03-22T00:29:50.132806332Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.1.12","type":"blocks","created_at":"2026-03-22T00:47:59.577804212Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.1.6","type":"blocks","created_at":"2026-03-21T23:57:25.327784097Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.1.7","type":"blocks","created_at":"2026-03-22T00:02:36.768707006Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.1.8","type":"blocks","created_at":"2026-03-22T00:10:27.620062865Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.1.9","type":"blocks","created_at":"2026-03-22T00:17:52.363446158Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.7","type":"parent-child","created_at":"2026-03-21T23:38:22.378960630Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.7.1","type":"blocks","created_at":"2026-03-21T23:38:35.158585130Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.7.3","depends_on_id":"bd-j9jo3.7.2","type":"blocks","created_at":"2026-03-21T23:38:35.637453438Z","created_by":"ubuntu","metadata":"{}","thread_id":""}],"comments":[{"id":337,"issue_id":"bd-j9jo3.7.3","author":"ubuntu","text":"Watch-semantics follow-up: machine-consumer metadata should include stream or watch availability, event taxonomy hints, selector or filter affordances, heartbeat expectations, and enough metadata that an agent can distinguish idle, filtered, and degraded long-lived consumption without trial-and-error.","created_at":"2026-03-22T00:49:03Z"}]}
 {"id":"bd-j9jo3.8","title":"robot-redesign/parity: REST, dashboard, and transport parity","description":"Repoint REST handlers, dashboard summaries, and transport-specific attention streams at the same projection and contract layer used by robot CLI surfaces. This epic exists so the redesign does not improve CLI JSON while leaving server and dashboard code to rot on older assembly paths.","design":"Parity here means semantic parity, not byte-for-byte identical payloads. All consumers should agree on section names, degraded-state meaning, cursor semantics, and next-action cues even when the final presentation differs by transport.\\n\\nThe long-term payoff is that future changes land once in the projection/registry layer instead of being copied into multiple stacks.","acceptance_criteria":"This epic is complete when REST, SSE, WebSocket, dashboard markdown, and other summary renderers consume the same normalized contract and stop carrying divergent logic.","notes":"Transport parity is not optional cleanup. It is part of making the robot contract trustworthy.","status":"open","priority":4,"issue_type":"epic","estimated_minutes":240,"created_at":"2026-03-21T23:32:12.693053559Z","created_by":"ubuntu","updated_at":"2026-03-22T00:10:20.760605701Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["parity","robot-redesign"],"dependencies":[{"issue_id":"bd-j9jo3.8","depends_on_id":"bd-j9jo3","type":"parent-child","created_at":"2026-03-21T23:32:12.693053559Z","created_by":"ubuntu","metadata":"{}","thread_id":""}],"comments":[{"id":320,"issue_id":"bd-j9jo3.8","author":"ubuntu","text":"Future self: if one transport has a field or section nobody else has, ask whether it belongs in the shared projection model instead.","created_at":"2026-03-21T23:32:13Z"}]}
 {"id":"bd-j9jo3.8.1","title":"robot-redesign/parity: repoint REST handlers at the shared projection model","description":"Refactor REST handlers to serve the same shared runtime sections and semantics as the CLI robot surfaces. This task exists because transport parity should come from shared projection logic, not from parallel implementations that happen to look similar for a while.","design":"The work should make server handlers thin adapters over the same projection-backed surfaces used by CLI robot commands. It should also ensure REST consumers get the same freshness, schema, degraded-state, action-handoff, request-correlation or idempotency, operator-attention-state, explainability, and recoverable-error semantics as CLI consumers, including aggregated attention behavior, diagnostic drill-down access, and evidence references where the contract exposes them. The purpose is eliminating parallel truth, not merely exposing more endpoints.","acceptance_criteria":"This task is complete when REST handlers clearly project from the shared model and surface contracts no longer depend on transport-specific assembly logic, including for correlated actuation outcomes, compacted attention semantics, and durable operator overrides.","notes":"Paritizing REST early prevents the redesign from calcifying into a CLI-only architecture that later has to be copied again.","status":"open","priority":1,"issue_type":"task","estimated_minutes":180,"created_at":"2026-03-21T23:38:23.380385406Z","created_by":"ubuntu","updated_at":"2026-03-22T00:31:45.295291020Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["parity","rest","robot-redesign"],"dependencies":[{"issue_id":"bd-j9jo3.8.1","depends_on_id":"bd-j9jo3.1.10","type":"blocks","created_at":"2026-03-22T00:23:34.175138941Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-j9jo3.8.1","depends_on_id":"bd-j9jo3.1.11","type":"blocks","created_at":"2026-03-22T00:29:50.816308766Z","created_by":"ubuntu",